import React, { useState, useEffect, useRef } from 'react';

// Enhanced movie poster fallback
const fallbackImages = [
  'https://images.unsplash.com/photo-1489599849228-13e67d91ebff?w=300&h=450&fit=crop',
  'https://images.unsplash.com/photo-1517604931442-7e0c6ed2963c?w=300&h=450&fit=crop',
  'https://images.unsplash.com/photo-1594908900066-3f47337549d8?w=300&h=450&fit=crop',
  'https://images.unsplash.com/photo-1493225457124-a3eb161ffa5f?w=300&h=450&fit=crop',
  'https://images.unsplash.com/photo-1513941231169-2b8d6ce5dd21?w=300&h=450&fit=crop',
];

const getFallbackImage = () => fallbackImages[Math.floor(Math.random() * fallbackImages.length)];

const MovieManager = () => {
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [filterRating, setFilterRating] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  // Upload state
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [previewImage, setPreviewImage] = useState(null);
  const [uploadedPoster, setUploadedPoster] = useState('');
  const fileInputRef = useRef(null);

  const [formData, setFormData] = useState({
    title: '',
    genre: '',
    rating: '',
    recommendation: 'Yes'
  });

  useEffect(() => {
    fetchMovies();
  }, [filterRating]);

  const fetchMovies = async () => {
    setLoading(true);
    try {
      const url = filterRating ? `http://localhost:5000/movies?rating=${filterRating}` : 'http://localhost:5000/movies';
      const response = await fetch(url);
      const data = await response.json();
      setMovies(data);
    } catch (error) {
      console.error('Error fetching movies:', error);
      alert('Failed to fetch movies');
    }
    setLoading(false);
  };

  const handleImageUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    // Preview
    const reader = new FileReader();
    reader.onloadend = () => {
      setPreviewImage(reader.result);
    };
    reader.readAsDataURL(file);

    setUploading(true);
    const formDataUpload = new FormData();
    formDataUpload.append('poster', file);

    try {
      const response = await fetch('http://localhost:5000/movies/upload', {
        method: 'POST',
        body: formDataUpload,
      });

      const result = await response.json();
      if (response.ok) {
        setUploadedPoster(result.path);
        setUploadProgress(100);
        alert('Image uploaded! Ready to save.');
      } else {
        alert(result.error || 'Upload failed');
      }
    } catch (error) {
      alert('Upload failed: ' + error.message);
    }
    setUploading(false);
    setUploadProgress(0);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.title || !formData.genre || !formData.rating) {
      alert('Title, genre, rating required');
      return;
    }

    try {
      const submitData = {
        title: formData.title,
        genre: formData.genre,
        rating: parseInt(formData.rating),
        recommendation: formData.recommendation,
        poster: uploadedPoster || null
      };

      if (editingId) {
        const response = await fetch(`http://localhost:5000/movies/${editingId}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(submitData)
        });
        const updated = await response.json();
        setMovies(movies.map(m => m.id === editingId ? updated : m));
      } else {
        const response = await fetch('http://localhost:5000/movies', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(submitData)
        });
        const newMovie = await response.json();
        setMovies([...movies, newMovie]);
      }
      resetForm();
    } catch (error) {
      alert('Save failed');
    }
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingId(null);
    setFormData({ title: '', genre: '', rating: '', recommendation: 'Yes' });
    setPreviewImage(null);
    setUploadedPoster('');
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleEdit = (movie) => {
    setFormData({
      title: movie.title,
      genre: movie.genre,
      rating: movie.rating,
      recommendation: movie.recommendation
    });
    setUploadedPoster(movie.poster || '');
    setEditingId(movie.id);
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (!confirm('Delete movie?')) return;
    try {
      await fetch(`http://localhost:5000/movies/${id}`, { method: 'DELETE' });
      setMovies(movies.filter(m => m.id !== id));
    } catch (error) {
      alert('Delete failed');
    }
  };

  const filteredMovies = movies.filter(movie => 
    movie.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    movie.genre.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const genreColors = {
    'Sci-Fi': 'from-blue-500/20 to-cyan-500/20',
    'Action': 'from-red-500/20 to-orange-500/20',
    'Drama': 'from-purple-500/20 to-pink-500/20',
    'Comedy': 'from-yellow-500/20 to-orange-500/20',
    'Horror': 'from-gray-800/50 to-red-500/20',
    'Romance': 'from-pink-500/20 to-rose-500/20',
  };

  const getRatingColor = (rating) => rating >= 4 ? 'text-green-400' : rating >= 3 ? 'text-yellow-400' : 'text-red-400';

  return (
    <div className="space-y-12 p-6 lg:p-12">
      {/* Header */}
      <header className="flex items-center justify-between">
        <div>
          <h2 className="text-5xl font-black bg-gradient-to-r from-yellow-400 to-orange-500 bg-clip-text text-transparent">
            🎞️ Movie Collection
          </h2>
          <p className="text-xl text-slate-400 mt-2">Upload custom posters & organize favorites</p>
        </div>
        <button
          onClick={() => setShowForm(!showForm)}
          className="px-10 py-4 bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white font-black rounded-2xl shadow-xl hover:shadow-emerald-500/25 transition-all border border-emerald-500/30 text-lg"
        >
          + Add Movie
        </button>
      </header>

      {/* Search & Filter */}
      <div className="flex flex-col lg:flex-row gap-4 glass p-8 rounded-3xl">
        <input
          type="text"
          placeholder="🔍 Search by title or genre..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="flex-1 form-input px-12 py-4 text-lg rounded-2xl"
        />
        <select
          value={filterRating}
          onChange={(e) => setFilterRating(e.target.value)}
          className="form-input px-8 py-4 text-lg rounded-2xl"
        >
          <option>All Ratings</option>
          <option value="1">⭐</option>
          <option value="2">⭐⭐</option>
          <option value="3">⭐⭐⭐</option>
          <option value="4">⭐⭐⭐⭐</option>
          <option value="5">⭐⭐⭐⭐⭐</option>
        </select>
      </div>

      {/* Form */}
      {showForm && (
        <div className="glass p-12 rounded-3xl max-w-6xl mx-auto">
          <div className="flex items-center justify-between mb-12">
            <h3 className="text-4xl font-black bg-gradient-to-r from-purple-400 to-pink-500 bg-clip-text text-transparent">
              {editingId ? 'Edit Movie' : 'New Movie'}
            </h3>
            <button 
              onClick={resetForm}
              className="px-8 py-4 btn btn-secondary text-lg font-black"
            >
              Cancel
            </button>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-start mb-12">
            {/* Upload */}
            <div>
              <label className="form-label text-2xl mb-6 block">🖼️ Movie Poster</label>
              <div className="space-y-6">
                <input
                  ref={fileInputRef}
                  type="file"
                  accept="image/*"
                  onChange={handleImageUpload}
                  className="w-full h-48 border-2 border-dashed border-slate-600 rounded-2xl p-12 text-center text-lg hover:border-yellow-400/50 transition-all file:hidden file:mr-0 cursor-pointer bg-slate-800/50 hover:bg-slate-700/50"
                />
                {uploading && (
                  <div className="w-full bg-slate-800 rounded-full h-4">
                    <div 
                      className="bg-gradient-to-r from-emerald-500 to-teal-500 h-4 rounded-full transition-all"
                      style={{ width: `${uploadProgress}%` }}
                    />
                  </div>
                )}
                {uploadedPoster && (
                  <div className="p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-xl text-emerald-400 font-mono text-sm">
                    ✅ {uploadedPoster.split('/').pop()}
                  </div>
                )}
              </div>
            </div>

            {/* Preview */}
            {previewImage && (
              <div className="relative">
                <img src={previewImage} alt="Preview" className="w-full h-96 object-cover rounded-3xl shadow-2xl" />
                <div className="absolute top-4 right-4 bg-emerald-500 text-white px-4 py-2 rounded-xl font-bold text-sm shadow-lg">
                  Preview
                </div>
              </div>
            )}
          </div>

          {/* Form fields */}
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div>
              <label className="form-label text-xl mb-4 block">Movie Title</label>
              <input
                type="text"
                placeholder="Enter title..."
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                className="form-input text-xl py-6 rounded-2xl"
                required
              />
            </div>
            <div>
              <label className="form-label text-xl mb-4 block">Genre</label>
              <input
                type="text"
                placeholder="Sci-Fi, Action, Drama..."
                value={formData.genre}
                onChange={(e) => setFormData({ ...formData, genre: e.target.value })}
                className="form-input text-xl py-6 rounded-2xl"
                required
              />
            </div>
            <div>
              <label className="form-label text-xl mb-4 block">Rating</label>
              <input
                type="number"
                min="1"
                max="5"
                value={formData.rating}
                onChange={(e) => setFormData({ ...formData, rating: e.target.value })}
                className="form-input text-4xl font-black text-yellow-400 py-6 rounded-2xl"
                required
              />
            </div>
            <div>
              <label className="form-label text-xl mb-4 block">Recommendation</label>
              <select
                value={formData.recommendation}
                onChange={(e) => setFormData({ ...formData, recommendation: e.target.value })}
                className="form-input text-xl py-6 rounded-2xl font-semibold"
              >
                <option value="Yes">Yes ✓</option>
                <option value="No">No ✗</option>
              </select>
            </div>
            <div className="md:col-span-2 flex gap-6 pt-8">
              <button type="submit" className="flex-1 btn btn-primary py-6 text-xl font-black shadow-2xl hover:shadow-yellow-500/25">
                {editingId ? 'Update Movie' : 'Add Movie'}
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Grid */}
      {loading ? (
        <div className="flex items-center justify-center h-96">
          <div className="w-24 h-24 border-4 border-slate-700 border-t-yellow-500 rounded-full animate-spin"></div>
        </div>
      ) : filteredMovies.length === 0 ? (
        <div className="text-center py-32 glass rounded-3xl p-12">
          <div className="text-8xl mb-8">🎥</div>
          <h3 className="text-4xl font-black mb-4 text-slate-200">No Movies</h3>
          <p className="text-xl text-slate-500 max-w-lg mx-auto">Search something or add your first film</p>
        </div>
      ) : (
        <div className="grid-responsive gap-8">
          {filteredMovies.map((movie, index) => (
            <div
              key={movie.id}
              className="card group p-8 hover:shadow-2xl hover:-translate-y-2 transition-all duration-500 rounded-3xl"
            >
              {/* Poster */}
              <div className="relative mb-8 h-80 rounded-2xl overflow-hidden bg-slate-800/50 group-hover:ring-4 group-hover:ring-yellow-400/20">
                <img 
                  src={movie.poster ? `http://localhost:5000${movie.poster}` : getFallbackImage()}
                  alt={movie.title}
                  className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                  onError={(e) => e.target.src = getFallbackImage()}
                />
                <div className={`absolute inset-0 bg-gradient-to-t from-slate-900/70 opacity-0 group-hover:opacity-100 transition-opacity ${genreColors[movie.genre]}`} />
                <div className="absolute top-6 left-6 z-10">
                  <span className="px-4 py-2 rounded-full text-sm font-black bg-white/10 backdrop-blur">
                    {movie.genre}
                  </span>
                </div>
                <div className={`absolute top-6 right-6 z-10 ${getRatingColor(movie.rating)} px-4 py-2 rounded-full text-lg font-black bg-white/10 backdrop-blur shadow-lg`}>
                  {'⭐'.repeat(movie.rating)}
                </div>
              </div>

              {/* Content */}
              <h3 className="text-3xl font-black mb-4 group-hover:text-yellow-400 transition-colors line-clamp-2">
                {movie.title}
              </h3>
              
              <div className="space-y-4 mb-10 text-slate-400 text-lg">
                <div className="flex items-center justify-between">
                  <span>Rating</span>
                  <span className="text-2xl font-black text-yellow-400">{movie.rating}/5</span>
                </div>
                <div className="flex items-center justify-between">
                  <span>Recommend</span>
                  <span className={`px-4 py-2 rounded-full font-black text-sm ${movie.recommendation === 'Yes' ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-400/30' : 'bg-red-500/20 text-red-400 border border-red-400/30'}`}>
                    {movie.recommendation}
                  </span>
                </div>
                {movie.poster && (
                  <div className="text-sm opacity-80">
                    📸 Custom poster
                  </div>
                )}
              </div>

              {/* Actions */}
              <div className="flex gap-4 pt-8 border-t border-slate-800/50">
                <button
                  onClick={() => handleEdit(movie)}
                  className="flex-1 bg-gradient-to-r from-blue-500 to-blue-600 hover:from-blue-600 hover:to-blue-700 py-4 px-8 rounded-xl font-black text-white shadow-lg hover:shadow-blue-500/25 transition-all border border-blue-500/30"
                >
                  Edit
                </button>
                <button
                  onClick={() => handleDelete(movie.id)}
                  className="flex-1 bg-gradient-to-r from-red-500 to-red-600 hover:from-red-600 hover:to-red-700 py-4 px-8 rounded-xl font-black text-white shadow-lg hover:shadow-red-500/25 transition-all border border-red-500/30"
                >
                  Delete
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default MovieManager;
